import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/idea-community.CV-Uvcck.js";const a=JSON.parse(`{"title":"Configurando tu entorno de desarrollo","description":"Una guía paso a paso para como configurar un entorno de desarollo para crear mods usando Fabric.","frontmatter":{"title":"Configurando tu entorno de desarrollo","description":"Una guía paso a paso para como configurar un entorno de desarollo para crear mods usando Fabric.","authors":["IMB11","andrew6rant","SolidBlock-cn","modmuss50","daomephsta","liach","telepathicgrunt","2xsaiko","natanfudge","mkpoli","falseresync","asiekierka"],"authors-nogithub":["siglong"],"files":[]},"headers":[],"relativePath":"es_es/1.21.1/develop/getting-started/setting-up-a-development-environment.md","filePath":"versions/1.21.1/translated/es_es/develop/getting-started/setting-up-a-development-environment.md","lastUpdated":1761424914000}`);var o={name:`es_es/1.21.1/develop/getting-started/setting-up-a-development-environment.md`};function s(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Configurando tu entorno de desarrollo <a class="header-anchor" href="#h1" aria-label="Permalink to “Configurando tu entorno de desarrollo”">​</a></h1><p>Para empezar a desarollar mods usando Fabric, necesitarás configurar un entorno de desarrollo usando IntelliJ IDEA.</p><h2 id="instalar-java-17" tabindex="-1">Instalar Java 17 <a class="header-anchor" href="#instalar-java-17" aria-label="Permalink to “Instalar Java 17”">​</a></h2><p>Para desarrollar mods para Minecraft 1.20.4, necesitarás JDK 17.</p><p>Si necesitas ayuda instalando Java, puedes ver nuestras guías sobre la instalación de Java en la <a href="./../../players/index">sección de guías para jugadores</a></p><h2 id="instalando-intellij-idea" tabindex="-1">Instalando IntelliJ IDEA <a class="header-anchor" href="#instalando-intellij-idea" aria-label="Permalink to “Instalando IntelliJ IDEA”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Obviamente puedes usar otros IDEs, como Eclipse o Visual Studio Code, pero la mayoría de las páginas en esta documentación asumirán que estás usando IntelliJ IDEA - deberías visitar la documentación para tu IDE si estás usando alguno diferente.</p></div><p>Si no tienes IntelliJ IDEA instalado, puedes descargarlo desde la <a href="https://www.jetbrains.com/idea/download/" target="_blank" rel="noreferrer">página web oficial</a> - sigue los pasos de instalación para tu sistema operativo.</p><p>La edición de Comunidad de IntelliJ IDEA es gratis y de fuente abierta, y es la versión recomendada para desarrollar mods con Fabric.</p><p>Puede que tengas que deslizar la página hacia abajo para encontrar los enlaces para descargar la edición de Comunidad - se ve de la siguiente manera:</p><p><img src="/assets/develop/getting-started/idea-community.png" alt="Sugerencia de descarga de IntelliJ edición de Comunidad" loading="lazy"></p><h2 id="instalando-plugins-en-idea" tabindex="-1">Instalando <em>Plugins</em> en IDEA <a class="header-anchor" href="#instalando-plugins-en-idea" aria-label="Permalink to “Instalando Plugins en IDEA”">​</a></h2><p>Aunque estos plugins no son estrictamente necesarios, hacen el desarrollo de mods con Fabric mucho más fácil - deberías considerar instalarlos.</p><h3 id="minecraft-development" tabindex="-1">Minecraft Development <a class="header-anchor" href="#minecraft-development" aria-label="Permalink to “Minecraft Development”">​</a></h3><p>El plugin de Minecraft Development provee soporte para desarrollar mods con Fabric, y es el plugin más importante para instalar.</p><p>Puedes instalarlo abriendo IntelliJ IDEA, y luego navegando a <code>File &gt; Settings &gt; Plugins &gt; Marketplace Tab</code> - busca <code>Minecraft Development</code> en la barra de búsqueda, y luego haz clic en el botón de <code>Install</code> (Instalar).</p><p>Alternativamente, puedes descargarlo desde la <a href="https://plugins.jetbrains.com/plugin/8327-minecraft-development" target="_blank" rel="noreferrer">página web del plugin</a> y luego puedes instalarlo navegando a <code>File &gt; Settings &gt; Plutins &gt; Install Plugin from Disk</code>.</p>`,17)]])}var c=r(o,[[`render`,s]]);export{a as __pageData,c as default};